     1→/**
     2→ * T033: Disambiguation Stage Implementation
     3→ *
     4→ * Resolves conflicts between competing categories by applying pairwise adjustments
     5→ * when confidence gaps are below the threshold. Uses DISAMBIGUATOR attributes to
     6→ * help resolve close classification decisions.
     7→ *
     8→ * Reference: DisambiguationNode.js (pairwise adjustments for competing categories)
     9→ * Config: processing_config.settings.disambiguation.confidence_gap_threshold
    10→ * Logic: Pairwise adjustments per SCORING_LOGIC.md "Disambiguation Stage"
    11→ */
    12→
    13→import { EmailMessage } from '../types/email-message';
    14→import { AttributeContext } from '../types/attribute-context';
    15→import { CategoryConfiguration, AttributeRole } from '../types/category-configuration';
    16→import { DISAMBIGUATION_DEFAULTS } from '../config/constants';
    17→
    18→/**
    19→ * Result of disambiguation stage
    20→ */
    21→export interface DisambiguationResult {
    22→  competing_categories: CompetingCategoryPair[];
    23→  adjustments_applied: DisambiguationAdjustment[];
    24→  original_scores: Record<string, number>;
    25→  updated_scores: Record<string, number>;
    26→  score_deltas: Record<string, number>;
    27→  processing_duration_ms: number;
    28→  configuration_references: {
    29→    disambiguation_settings_path: string;
    30→    confidence_gap_threshold: number;
    31→  };
    32→  // Preserve previous stage data
    33→  [key: string]: unknown;
    34→}
    35→
    36→/**
    37→ * Competing category pair requiring disambiguation
    38→ */
    39→export interface CompetingCategoryPair {
    40→  category1: string;
    41→  category2: string;
    42→  score_gap: number;
    43→  requires_disambiguation: boolean;
    44→  subtype_competition?: boolean;
    45→}
    46→
    47→/**
    48→ * Disambiguation adjustment applied to a category
    49→ */
    50→export interface DisambiguationAdjustment {
    51→  category: string;
    52→  attribute: string;
    53→  role: AttributeRole;
    54→  adjustment_amount: number;
    55→  adjustment_reason: string;
    56→  confidence_factor: number;
    57→  decay_applied: boolean;
    58→  decay_factor?: number;
    59→}
    60→
    61→/**
    62→ * Disambiguation configuration
    63→ */
    64→interface DisambiguationConfig {
    65→  pairwise_adjustments: boolean;
    66→  confidence_gap_threshold: number;
    67→  max_adjustments_per_email?: number;
    68→  adjustment_decay_factor?: number;
    69→  enable_subtype_disambiguation?: boolean;
    70→}
    71→
    72→/**
    73→ * Execute disambiguation stage
    74→ *
    75→ * Analyzes candidate scores to identify competing categories and applies
    76→ * targeted adjustments using DISAMBIGUATOR attributes to resolve conflicts.
    77→ */
    78→export async function executeDisambiguation(
    79→  email: EmailMessage,
    80→  context: AttributeContext,
    81→  config: CategoryConfiguration
    82→): Promise<DisambiguationResult> {
    83→  const startTime = Date.now();
    84→
    85→  // Validate configuration
    86→  if (!config.processing_config?.settings?.disambiguation) {
    87→    throw new Error('Disambiguation configuration not found');
    88→  }
    89→
    90→  const disambiguationConfig = config.processing_config.settings.disambiguation;
    91→  validateDisambiguationConfig(disambiguationConfig);
    92→
    93→  // Extract candidate scores from email
    94→  const emailData = email as EmailMessage & Record<string, unknown>;
    95→  const candidateScores = (emailData.candidate_scores as Record<string, number>) || {};
    96→
    97→  const originalScores = { ...candidateScores };
    98→  const updatedScores = { ...candidateScores };
    99→
   100→  // If no scores or insufficient scores, skip disambiguation
   101→  if (Object.keys(candidateScores).length < 2) {
   102→    return createEmptyResult(originalScores, updatedScores, disambiguationConfig, startTime, emailData);
   103→  }
   104→
   105→  // Identify competing categories
   106→  const competingCategories = identifyCompetingCategories(candidateScores, disambiguationConfig);
   107→
   108→  // Apply disambiguation adjustments
   109→  const adjustmentsApplied: DisambiguationAdjustment[] = [];
   110→
   111→  if (competingCategories.length > 0) {
   112→    const adjustments = calculateDisambiguationAdjustments(competingCategories, context, config, disambiguationConfig);
   113→
   114→    // Apply adjustments to scores
   115→    for (const adjustment of adjustments) {
   116→      updatedScores[adjustment.category] = (updatedScores[adjustment.category] || 0) + adjustment.adjustment_amount;
   117→      adjustmentsApplied.push(adjustment);
   118→    }
   119→  }
   120→
   121→  // Calculate score deltas
   122→  const scoreDeltas: Record<string, number> = {};
   123→  for (const category of Object.keys(originalScores)) {
   124→    scoreDeltas[category] = (updatedScores[category] || 0) - (originalScores[category] || 0);
   125→  }
   126→
   127→  const processingDuration = Math.max(1, Date.now() - startTime);
   128→
   129→  // Build result
   130→  const result: DisambiguationResult = {
   131→    competing_categories: competingCategories,
   132→    adjustments_applied: adjustmentsApplied,
   133→    original_scores: originalScores,
   134→    updated_scores: updatedScores,
   135→    score_deltas: scoreDeltas,
   136→    processing_duration_ms: processingDuration,
   137→    configuration_references: {
   138→      disambiguation_settings_path: 'processing_config.settings.disambiguation',
   139→      confidence_gap_threshold: disambiguationConfig.confidence_gap_threshold,
   140→    },
   141→  };
   142→
   143→  // Preserve stage chain data
   144→  if ('candidate_scores' in emailData) {
   145→    result.candidate_scores = updatedScores; // Update with new scores
   146→  }
   147→  if ('stage_results' in emailData && emailData.stage_results) {
   148→    result.stage_results = {
   149→      ...(emailData.stage_results as Record<string, unknown>),
   150→      disambiguation: { completed: true },
   151→    };
   152→  }
   153→
   154→  return result;
   155→}
   156→
   157→/**
   158→ * Identify competing categories that require disambiguation
   159→ */
   160→function identifyCompetingCategories(
   161→  candidateScores: Record<string, number>,
   162→  config: DisambiguationConfig
   163→): CompetingCategoryPair[] {
   164→  const competingPairs: CompetingCategoryPair[] = [];
   165→  const categories = Object.entries(candidateScores).sort(([, a], [, b]) => b - a); // Sort by score descending
   166→
   167→  // Check all pairs for competition
   168→  for (let i = 0; i < categories.length; i++) {
   169→    for (let j = i + 1; j < categories.length; j++) {
   170→      const [category1, score1] = categories[i];
   171→      const [category2, score2] = categories[j];
   172→
   173→      const scoreGap = Math.abs(score1 - score2);
   174→
   175→      if (scoreGap <= config.confidence_gap_threshold) {
   176→        const isSubtypeCompetition = areSubtypesOfSameCategory(category1, category2);
   177→
   178→        // Skip subtype competition if disabled
   179→        if (
   180→          isSubtypeCompetition &&
   181→          !(config.enable_subtype_disambiguation ?? DISAMBIGUATION_DEFAULTS.ENABLE_SUBTYPE_DISAMBIGUATION)
   182→        ) {
   183→          continue;
   184→        }
   185→
   186→        competingPairs.push({
   187→          category1,
   188→          category2,
   189→          score_gap: scoreGap,
   190→          requires_disambiguation: true,
   191→          subtype_competition: isSubtypeCompetition,
   192→        });
   193→      }
   194→    }
   195→  }
   196→
   197→  return competingPairs;
   198→}
   199→
   200→/**
   201→ * Calculate disambiguation adjustments using DISAMBIGUATOR attributes
   202→ */
   203→function calculateDisambiguationAdjustments(
   204→  competingCategories: CompetingCategoryPair[],
   205→  context: AttributeContext,
   206→  config: CategoryConfiguration,
   207→  disambiguationConfig: DisambiguationConfig
   208→): DisambiguationAdjustment[] {
   209→  const adjustments: DisambiguationAdjustment[] = [];
   210→  const categoryAdjustmentCounts: Record<string, number> = {};
   211→
   212→  // Get all categories involved in competition
   213→  const involvedCategories = new Set<string>();
   214→  for (const pair of competingCategories) {
   215→    involvedCategories.add(pair.category1);
   216→    involvedCategories.add(pair.category2);
   217→  }
   218→
   219→  // Find DISAMBIGUATOR attributes for involved categories
   220→  for (const [attributeName, metadata] of Object.entries(context.detectionMetadata)) {
   221→    for (const categoryName of involvedCategories) {
   222→      const categoryKey = getCategoryKey(categoryName);
   223→      const subtypeKey = getSubtypeKey(categoryName);
   224→
   225→      const attributeRole = getAttributeRole(attributeName, categoryKey, subtypeKey, config);
   226→
   227→      if (attributeRole === 'DISAMBIGUATOR') {
   228→        // Check if we've hit the adjustment limit
   229→        if (
   230→          adjustments.length >=
   231→          (disambiguationConfig.max_adjustments_per_email || DISAMBIGUATION_DEFAULTS.MAX_ADJUSTMENTS_PER_EMAIL)
   232→        ) {
   233→          break;
   234→        }
