  version: z.string(),
  lastModified: z.date(),
  hash: z.string(),

  processing_config: z.object({
    version: z.number(),
    taxonomy_notes: z.string(),

    settings: z.object({
      initialization: z.object({
        apply_hard_assertions: z.boolean(),
        seed_category_scores: z.boolean(),
