    // Setup attribute context
    mockContext = {
      emailId: 'test-email-123',
      urgency: 'medium',
      domains: ['financial.com'],
      structuralPatterns: ['invoice_pattern'],
      temporalSignals: ['end_of_month'],
      detectionMetadata: {},
      influenceApplications: [],
      derivedAttributes: {},
      attributeRelationships: [],
    };

    // Setup category configuration with disambiguation settings
    mockConfig = {
      version: '1.0',
      updated: '2024-01-01',
      top_level_categories: {
        FINANCIAL: {
          subtypes: {
            BILLING: {
              rule_based_classification: {
                high_confidence: [],
                medium_confidence: [],
                low_confidence: [],
              },
            },
            INSURANCE: {
              rule_based_classification: {
                high_confidence: [],
                medium_confidence: [],
                low_confidence: [],
              },
            },
          },
        },
        PERSONAL: {
          subtypes: {
            FAMILY: {
              rule_based_classification: {
                high_confidence: [],
                medium_confidence: [],
                low_confidence: [],
